#ifndef NET_SOCKET_H
#define NET_SOCKET_H

#include <stdint.h>

typedef int net_sock_t;

#define NET_SOCK_INVALID   (-1)
#define NET_AF_INET        (2)
#define NET_SOCK_STREAM    (1)
#define NET_SOCK_DGRAM     (2)

typedef struct {
    uint8_t  family;    /* AF_INET only */
    uint16_t port;      /* host byte order */
    uint32_t addr;      /* IPv4 address, host byte order */
} net_sockaddr_t;

net_sock_t net_socket(uint8_t family, uint8_t type);
int        net_connect(net_sock_t sock, const net_sockaddr_t *addr);
int        net_send(net_sock_t sock, const uint8_t *buf, uint16_t len, uint8_t flags);
int        net_recv(net_sock_t sock, uint8_t *buf, uint16_t len, uint8_t flags);
int        net_close(net_sock_t sock);

#endif /* NET_SOCKET_H */

